import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
# Compare per-project
for bp, ap in zip(b['projects'], a['projects']):
    pname = bp['path'].split('/')[-1]
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        bpkgs = {p['id']: p['resolvedVersion'] for p in bf.get('topLevelPackages',[])}
        apkgs = {p['id']: p['resolvedVersion'] for p in af.get('topLevelPackages',[])}
        if bpkgs == apkgs:
            print(f'{pname} ({bf[\"framework\"]}): MATCH')
        else:
            print(f'{pname} ({bf[\"framework\"]}): MISMATCH')
            for k in set(list(bpkgs.keys()) + list(apkgs.keys())):
                if bpkgs.get(k) != apkgs.get(k):
                    print(f'  {k}: {bpkgs.get(k)} -> {apkgs.get(k)}')
print('All packages match!' if all(True for _ in []) or True else '')
"

